    Last_Transaction_Date IS NULL OR
    TransactionID IS NULL OR
    Transaction_Date IS NULL OR
    Transaction_Type IS NULL OR
    Transaction_Amount IS NULL OR
    Account_Balance_After_Transaction IS NULL OR
    Branch_ID IS NULL OR
